SELECT AVG(performance) AS average_performance
FROM stock_performance
WHERE stock_id = 1;

SELECT performance
FROM region_performance
WHERE region_id = 1 AND date = '1';

SELECT stock_id, COUNT(*) AS prediction_count
FROM model_predictions
GROUP BY stock_id;

SELECT AVG(performance) AS avg_performance
FROM industry_performance
WHERE industry_id = 1 AND date = '2023-10-01';

SELECT AVG(performance) AS avg_performance, MAX(price_change) AS max_price_change
FROM region_performance
WHERE region_id = 1;

SELECT AVG(volatility) AS average_volatility
FROM stock_market_data
WHERE stock_id = 0;
